import java.util.*;

public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    // Priority queue: [i, j, remaining_k, cost]
    PriorityQueue<long[]> pq = new PriorityQueue<>(Comparator.comparingLong(a -> a[3]));
    pq.offer(new long[]{0, 0, k, 0});

    // Visited: [i][j][remaining_k] -> min cost
    long[][][] visited = new long[m][n][(int)k + 1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            Arrays.fill(visited[i][j], Long.MAX_VALUE);
        }
    }
    visited[0][0][(int)k] = 0;

    int[][] dirs = {{0, 1}, {1, 0}}; // right and down

    while (!pq.isEmpty()) {
        long[] curr = pq.poll();
        int i = (int)curr[0];
        int j = (int)curr[1];
        int remK = (int)curr[2];
        long cost = curr[3];

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > visited[i][j][remK]) {
            continue;
        }

        // Normal moves
        for (int[] dir : dirs) {
            int ni = i + dir[0];
            int nj = j + dir[1];
            if (ni < m && nj < n) {
                long newCost = cost + grid[ni][nj];
                if (newCost < visited[ni][nj][remK]) {
                    visited[ni][nj][remK] = newCost;
                    pq.offer(new long[]{ni, nj, remK, newCost});
                }
            }
        }

        // Teleport moves
        if (remK > 0) {
            for (int ni = 0; ni < m; ni++) {
                for (int nj = 0; nj < n; nj++) {
                    if (grid[ni][nj] <= grid[i][j] && (ni != i || nj != j)) {
                        if (cost < visited[ni][nj][remK - 1]) {
                            visited[ni][nj][remK - 1] = cost;
                            pq.offer(new long[]{ni, nj, remK - 1, cost});
                        }
                    }
                }
            }
        }
    }

    return -1; // should not reach here if path exists
}
