    int m = grid.length;
    int n = grid[0].length;
    // Directions: down and right
    int[][] dirs = {{1, 0}, {0, 1}};

    // Priority queue for Dijkstra's algorithm: [cost, i, j, remaining_k]
    PriorityQueue<long[]> pq = new PriorityQueue<>((a, b) -> Long.compare(a[0], b[0]));
    pq.offer(new long[]{0, 0, 0, k});

    // Visited array to keep track of minimum cost and remaining k for each cell
    long[][][] minCost = new long[m][n][(int)k + 1];
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            for (int l = 0; l <= k; l++) {
                minCost[i][j][l] = Long.MAX_VALUE;
            }
        }
    }
    minCost[0][0][(int)k] = 0;

    while (!pq.isEmpty()) {
        long[] current = pq.poll();
        long cost = current[0];
        int i = (int)current[1];
        int j = (int)current[2];
        int remainingK = (int)current[3];

        if (i == m - 1 && j == n - 1) {
            return cost;
        }

        if (cost > minCost[i][j][remainingK]) {
            continue;
        }

        // Explore normal moves (down and right)
        for (int[] dir : dirs) {
            int ni = i + dir[0];
            int nj = j + dir[1];
            if (ni < m && nj < n) {
                long newCost = cost + grid[ni][nj];
                if (newCost < minCost[ni][nj][remainingK]) {
                    minCost[ni][nj][remainingK] = newCost;
                    pq.offer(new long[]{newCost, ni, nj, remainingK});
                }
            }
        }

        // Explore teleport moves if remainingK > 0
        if (remainingK > 0) {
            for (int ni = 0; ni < m; ni++) {
