                    if (grid[ni][nj] <= grid[i][j] && (ni != i || nj != j)) {
                        long newCost = cost;
                        if (newCost < minCost[ni][nj][remainingK - 1]) {
                            minCost[ni][nj][remainingK - 1] = newCost;
                            pq.offer(new long[]{newCost, ni, nj, remainingK - 1});
                        }
                    }
                }
            }
        }
    }

    return -1; // Should not reach here if path exists
}
